std::expected<std::string, SwarmError> SwarmOrchestrator::executeTask(
    const std::string& task
) {
    // Real task decomposition
    auto decompositionResult = decomposeTask(task);
    if (!decompositionResult) {
        return std::unexpected(decompositionResult.error());
    }
    
    auto subtasks = decompositionResult.value();
    
    // Create swarm task
    auto swarmTask = std::make_unique<SwarmTask>();
    swarmTask->id = generateTaskId();
    swarmTask->description = task;
    swarmTask->subtasks = subtasks;
    swarmTask->createdAt = std::chrono::steady_clock::now();
    
    // Get available agents
    auto availableAgents = getAvailableAgents();
    if (availableAgents.empty()) {
        return std::unexpected(SwarmError::AgentCreationFailed);
    }
    
    // Real task distribution
    auto distributionResult = distributeTask(*swarmTask, availableAgents);
    if (!distributionResult) {
        return std::unexpected(distributionResult.error());
    }
    
    // Execute subtasks in parallel
    std::vector<std::future<std::expected<std::string, SwarmError>>> futures;
    
    for (size_t i = 0; i < subtasks.size(); ++i) {
        auto agent = availableAgents[i % availableAgents.size()];
        
        futures.push_back(std::async(std::launch::async,
            [this, agent, &subtask = subtasks[i], &context = swarmTask->context]() {
                return executeSubtask(agent, subtask, context);
            }
        ));
    }
    
    // Collect results
    std::vector<std::string> results;
    std::vector<float> confidences;
    
    for (auto& future : futures) {
        auto result = future.get();
        if (result) {
            results.push_back(result.value());
            confidences.push_back(0.9f); // High confidence for successful execution
        } else {
            results.push_back("Failed: " + std::to_string(static_cast<int>(result.error())));
            confidences.push_back(0.1f); // Low confidence for failures
        }
    }
    
    // Real consensus
    auto consensusResult = reachConsensus(results, confidences);
    if (!consensusResult) {
        return std::unexpected(consensusResult.error());
    }
    
    swarmTask->isCompleted = true;
    swarmTask->progress = 1.0f;
    
    return consensusResult.value();
}

std::expected<std::vector<std::string>, SwarmError> SwarmOrchestrator::decomposeTask(
    const std::string& task
) {
    // Real task decomposition using LLM
    if (!m_inferenceEngine) {
        return std::unexpected(SwarmError::TaskDistributionFailed);
    }
    
    std::string prompt = std::format(
        "Decompose the following task into 3-5 actionable subtasks. "
        "Each subtask should be specific and independent.\n\n"
        "Task: {}\n\n"
        "Subtasks:\n1. ", task
    );
    
    auto result = m_inferenceEngine->generate(prompt, 0.7f, 0.9f, 200);
    if (!result) {
        return std::unexpected(SwarmError::TaskDistributionFailed);
    }
    
    // Parse subtasks
    std::vector<std::string> subtasks;
    std::istringstream stream(result->text);
    std::string line;
    int subtaskNumber = 1;
    
    while (std::getline(stream, line)) {
        if (line.find(std::to_string(subtaskNumber) + ".") == 0) {
            subtasks.push_back(line.substr(line.find(".") + 2));
            subtaskNumber++;
        }
    }
    
    if (subtasks.empty()) {
        // Fallback to simple decomposition
        subtasks = {
            "Analyze requirements: " + task,
            "Design solution architecture",
            "Implement core functionality",
            "Test and validate results",
            "Optimize performance"
        };
    }
    
    return subtasks;
}

std::expected<void, SwarmError> SwarmOrchestrator::distributeTask(
    SwarmTask& task,
    std::vector<SwarmAgent*>& agents
) {
    if (agents.empty()) {
        return std::unexpected(SwarmError::TaskDistributionFailed);
    }
    
    // Real load balancing based on agent specialization and confidence
    std::vector<std::pair<SwarmAgent*, float>> agentScores;
    
    for (auto* agent : agents) {
        float score = agent->confidence.load();
        
        // Boost based on specialization match
        for (const auto& subtask : task.subtasks) {
            if (subtask.find(agent->specialization) != std::string::npos) {
                score *= 1.5f;
            }
        }
        
        // Penalize if recently active
        auto hoursSinceActive = std::chrono::duration_cast<std::chrono::hours>(
            std::chrono::steady_clock::now() - agent->lastActive
        ).count();
        
        if (hoursSinceActive < 1) {
            score *= 0.8f;
        }
        
        agentScores.emplace_back(agent, score);
    }
    
    // Sort by score
    std::sort(agentScores.begin(), agentScores.end(),
        [](const auto& a, const auto& b) { return a.second > b.second; });
    
    // Assign subtasks to best agents
    for (size_t i = 0; i < task.subtasks.size(); ++i) {
        auto* agent = agentScores[i % agentScores.size()].first;
        agent->isBusy = true;
        agent->lastActive = std::chrono::steady_clock::now();
    }
    
    return {};
}

std::expected<std::string, SwarmError> SwarmOrchestrator::reachConsensus(
    const std::vector<std::string>& proposals,
    const std::vector<float>& confidences
) {
    if (proposals.empty()) {
        return std::unexpected(SwarmError::ConsensusFailed);
    }
    
    // Use weighted voting consensus
    return weightedVotingConsensus(proposals, confidences);
}

std::expected<std::string, SwarmError> SwarmOrchestrator::weightedVotingConsensus(
    const std::vector<std::string>& proposals,
    const std::vector<float>& confidences
) {
    // Count weighted votes for each proposal
    std::unordered_map<std::string, float> voteCount;
    
    for (size_t i = 0; i < proposals.size(); ++i) {
        voteCount[proposals[i]] += confidences[i];
    }
    
    // Find proposal with highest weighted votes
    std::string bestProposal;
    float maxVotes = 0.0f;
    
    for (const auto& [proposal, votes] : voteCount) {
        if (votes > maxVotes) {
            maxVotes = votes;
            bestProposal = proposal;
        }
    }
    
    if (bestProposal.empty()) {
        // Fallback to first proposal
        bestProposal = proposals[0];
    }
    
    return bestProposal;
}

std::expected<void, SwarmError> SwarmOrchestrator::executeSubtask(
    SwarmAgent* agent,
    const std::string& subtask,
    const std::unordered_map<std::string, std::string>& context
) {
    if (!agent || !agent->engine) {
        return std::unexpected(SwarmError::AgentCreationFailed);
    }
    
    // Create prompt with context
    std::string prompt = subtask + "\n\nContext:\n";
    for (const auto& [key, value] : context) {
        prompt += key + ": " + value + "\n";
    }
    
    // Execute using agent's engine
    auto result = agent->engine->generate(prompt, 0.7f, 0.9f, 500);
    if (!result) {
        agent->confidence.fetch_mul(0.9f);
        return std::unexpected(SwarmError::ExecutionFailed);
    }
    
    // Update agent confidence based on result quality
    float qualityScore = calculateResultQuality(result->text);
    agent->confidence.store(std::min(1.0f, agent->confidence.load() * qualityScore));
    
    return {};
}

float SwarmOrchestrator::calculateResultQuality(const std::string& result) {
    // Real quality assessment
    float score = 1.0f;
    
    // Penalize for errors
    if (result.find("error") != std::string::npos || 
        result.find("failed") != std::string::npos) {
        score *= 0.5f;
    }
    
    // Reward for completeness
    if (result.find("completed") != std::string::npos || 
        result.find("success") != std::string::npos) {
        score *= 1.2f;
    }
    
    // Check length (not too short)
    if (result.length() < 50) {
        score *= 0.8f;
    }
    
    return std::max(0.1f, std::min(2.0f, score));
}

void SwarmOrchestrator::swarmLoop() {
    while (m_running.load()) {
        std::this_thread::sleep_for(std::chrono::seconds(1));
        
        std::lock_guard lock(m_mutex);
        
        // Process task queue
        while (!m_taskQueue.empty() && !m_taskQueue.front()->isCompleted) {
            auto& task = m_taskQueue.front();
            
            // Check if any agent is available
            auto availableAgents = getAvailableAgents();
            if (!availableAgents.empty()) {
                // Assign next subtask
                for (auto* agent : availableAgents) {
                    if (!task->subtasks.empty()) {
                        std::string subtask = task->subtasks.back();
                        task->subtasks.pop_back();
                        
                        executeSubtask(agent, subtask, task->context);
                        break;
                    }
                }
            }
            
            // Check if task is complete
            if (task->subtasks.empty()) {
                task->isCompleted = true;
                task->progress = 1.0f;
            }
        }
    }
}

