        if (!validationResult) {
            // Backtrack and try alternative
            auto backtrackResult = backtrack(chain, chain.steps.size() - 1);
            if (!backtrackResult) {
                return std::unexpected(backtrackResult.error());
            }
            chain = backtrackResult.value();
            continue;
        }
        
        step.isValidated = validationResult.value();
        
        // Calculate confidence
        auto confidenceResult = calculateStepConfidence(step, chain);
        if (confidenceResult) {
            step.confidence = confidenceResult.value();
        }
        
        chain.steps.push_back(step);
        
        // Check if goal is reached
        if (step.content.find(goal) != std::string::npos || 
            step.conclusions.contains(goal)) {
            chain.isComplete = true;
            chain.endTime = std::chrono::steady_clock::now();
        }
        
        stepCount++;
    }
    
    if (stepCount >= MAX_STEPS) {
        return std::unexpected(ChainError::MaxDepthExceeded);
    }
    
    // Calculate overall confidence
    float totalConfidence = 0.0f;
    for (const auto& step : chain.steps) {
        totalConfidence += step.confidence;
    }
    chain.overallConfidence = totalConfidence / chain.steps.size();
    
    return chain;
}

std::expected<ThoughtStep, ChainError> ChainOfThought::generateNextStep(
    const ReasoningChain& chain,
    const std::vector<ThoughtStep>& previousSteps
) {
    ThoughtStep step;
    step.id = generateStepId();
    step.timestamp = std::chrono::steady_clock::now();
    
    // Create prompt based on previous steps
    std::string prompt = "Goal: " + chain.goal + "\n\n";
    prompt += "Context:\n";
    for (const auto& [key, value] : chain.context) {
        prompt += key + ": " + value + "\n";
    }
    
    prompt += "\nPrevious reasoning:\n";
    for (const auto& prevStep : previousSteps) {
        prompt += prevStep.id + ": " + prevStep.content + "\n";
        prompt += "Reasoning: " + prevStep.reasoning + "\n\n";
    }
    
    prompt += "Next reasoning step:\n";
    
    // Generate using inference engine
    auto result = m_inferenceEngine->generate(prompt, 0.7f, 0.9f, 300);
    if (!result) {
        return std::unexpected(ChainError::StepGenerationFailed);
    }
    
    // Parse generated step
    std::string generated = result->text;
    step.content = generated.substr(0, generated.find("\n"));
    step.reasoning = "Generated based on previous steps";
    step.confidence = 0.8f; // Default confidence
    
    // Extract premises and conclusions
    size_t premisePos = generated.find("Premise:");
    if (premisePos != std::string::npos) {
        size_t endPos = generated.find("\n", premisePos);
        step.premises.push_back(generated.substr(premisePos + 8, endPos - premisePos - 8));
    }
    
    size_t conclusionPos = generated.find("Conclusion:");
    if (conclusionPos != std::string::npos) {
        size_t endPos = generated.find("\n", conclusionPos);
        step.conclusions.push_back(generated.substr(conclusionPos + 11, endPos - conclusionPos - 11));
    }
    
    return step;
}

std::expected<bool, ChainError> ChainOfThought::validateStep(
    const ThoughtStep& step,
    const ReasoningChain& chain
) {
    // Real logical validation
    auto consistencyResult = checkLogicalConsistency(step, chain);
    if (!consistencyResult) {
        return std::unexpected(consistencyResult.error());
    }
    
    if (!consistencyResult.value()) {
        return false;
    }
    
    // Check for contradictions
    auto contradictionsResult = identifyContradictions(chain);
    if (!contradictionsResult) {
        return std::unexpected(contradictionsResult.error());
    }
    
    auto contradictions = contradictionsResult.value();
    for (const auto& contradiction : contradictions) {
        if (step.content.find(contradiction) != std::string::npos) {
            return false; // Step contradicts previous reasoning
        }
    }
    
    return true;
}

std::expected<ReasoningChain, ChainError> ChainOfThought::backtrack(
    ReasoningChain& chain,
    size_t stepIndex
) {
    if (stepIndex >= chain.steps.size()) {
        return std::unexpected(ChainError::BacktrackingFailed);
    }
    
    // Remove steps from index onward
    chain.steps.resize(stepIndex);
    
    // Generate alternative step
    auto alternativeResult = generateNextStep(chain, chain.steps);
    if (!alternativeResult) {
        return std::unexpected(alternativeResult.error());
    }
    
    auto& alternativeStep = alternativeResult.value();
    alternativeStep.isRevised = true;
    alternativeStep.confidence *= 0.8f; // Lower confidence for revised steps
    
    chain.steps.push_back(alternativeStep);
    
    return chain;
}

std::expected<std::string, ChainError> ChainOfThought::generateExplanation(
    const ReasoningChain& chain
) {
    std::string explanation = "Reasoning for: " + chain.goal + "\n\n";
    
    for (const auto& step : chain.steps) {
        explanation += step.id + ": " + step.content + "\n";
        explanation += "Confidence: " + std::to_string(step.confidence) + "\n";
        
        if (!step.reasoning.empty()) {
            explanation += "Reasoning: " + step.reasoning + "\n";
        }
        
        if (!step.premises.empty()) {
            explanation += "Premises:\n";
            for (const auto& premise : step.premises) {
                explanation += "  - " + premise + "\n";
            }
        }
        
        if (!step.conclusions.empty()) {
            explanation += "Conclusions:\n";
            for (const auto& conclusion : step.conclusions) {
                explanation += "  - " + conclusion + "\n";
            }
        }
        
        if (step.isRevised) {
            explanation += "(Revised)\n";
        }
        
        explanation += "\n";
    }
    
    explanation += "Overall confidence: " + std::to_string(chain.overallConfidence) + "\n";
    
    return explanation;
}

