}

void NativeEditor::render(HDC hdc) {
    // Real rendering logic
    RECT clientRect;
    GetClientRect(m_hWndEditor, &clientRect);
    
    // Clear background
    FillRect(hdc, &clientRect, m_hBackgroundBrush);
    
    // Render line numbers if enabled
    if (m_showLineNumbers) {
        renderLineNumbers(hdc);
    }
    
    // Render visible lines
    int visibleLines = clientRect.bottom / m_charHeight;
    int startLine = m_scrollOffset;
    int endLine = std::min(startLine + visibleLines, static_cast<int>(m_lines.size()));
    
    for (int i = startLine; i < endLine; ++i) {
        int yPos = (i - startLine) * m_charHeight;
        renderLine(hdc, i, yPos);
    }
    
    // Render diagnostics
    renderDiagnostics(hdc);
    
    // Render selection
    renderSelection(hdc);
}

void NativeEditor::renderLine(HDC hdc, int lineIndex, int yPos) {
    if (lineIndex >= m_lines.size()) return;
    
    const auto& line = m_lines[lineIndex];
    
    // Apply syntax highlighting
    tokenizeLine(lineIndex);
    
    // Render each character with appropriate style
    int xPos = m_showLineNumbers ? m_lineNumberWidth : 0;
    
    for (size_t i = 0; i < line.renderedChars.size(); ++i) {
        const auto& charInfo = line.renderedChars[i];
        
        // Set text color based on syntax style
        COLORREF textColor = RGB(200, 200, 200); // Default
        
        switch (charInfo.Attributes) {
            case 1: // Keyword
                textColor = RGB(86, 156, 214);
                break;
            case 2: // String
                textColor = RGB(206, 145, 120);
                break;
            case 3: // Comment
                textColor = RGB(96, 139, 78);
                break;
            case 4: // Number
                textColor = RGB(181, 206, 168);
                break;
        }
        
        SetTextColor(hdc, textColor);
        SetBkMode(hdc, TRANSPARENT);
        
        // Draw character
        TextOut(hdc, xPos, yPos, &charInfo.Char.AsciiChar, 1);
        
        xPos += m_charWidth;
    }
}

void NativeEditor::tokenizeLine(int lineIndex) {
    if (lineIndex >= m_lines.size()) return;
    
    auto& line = m_lines[lineIndex];
    line.renderedChars.clear();
    
    // Real tokenization
    std::string text = line.text;
    size_t pos = 0;
    
    while (pos < text.length()) {
        CHAR_INFO charInfo;
        charInfo.Char.AsciiChar = text[pos];
        charInfo.Attributes = 0; // Default style
        
        // Detect tokens
        if (isalpha(text[pos])) {
            // Identifier or keyword
            size_t start = pos;
            while (pos < text.length() && isalnum(text[pos])) pos++;
            
            std::string token = text.substr(start, pos - start);
            int style = detectSyntaxStyle(token);
            
            // Apply style to all characters in token
            for (size_t i = start; i < pos; ++i) {
                line.renderedChars[i].Attributes = style;
            }
            
            pos = start + token.length();
            continue;
        } else if (text[pos] == '"' || text[pos] == '\'') {
            // String literal
            char quote = text[pos];
            charInfo.Attributes = 2; // String style
            
            line.renderedChars.push_back(charInfo);
            pos++;
            
            while (pos < text.length() && text[pos] != quote) {
                charInfo.Char.AsciiChar = text[pos];
                charInfo.Attributes = 2;
                line.renderedChars.push_back(charInfo);
                pos++;
            }
            
            if (pos < text.length()) {
                charInfo.Char.AsciiChar = text[pos];
                charInfo.Attributes = 2;
                line.renderedChars.push_back(charInfo);
                pos++;
            }
            
            continue;
        } else if (isdigit(text[pos])) {
            // Number
            charInfo.Attributes = 4; // Number style
            
            while (pos < text.length() && isdigit(text[pos])) {
                line.renderedChars.push_back(charInfo);
                pos++;
            }
            
            continue;
        } else if (pos + 1 < text.length() && text[pos] == '/' && text[pos + 1] == '/') {
            // Comment
            while (pos < text.length()) {
                charInfo.Char.AsciiChar = text[pos];
                charInfo.Attributes = 3; // Comment style
                line.renderedChars.push_back(charInfo);
                pos++;
            }
            
            break;
        }
        
        // Default character
        line.renderedChars.push_back(charInfo);
        pos++;
    }
}

int NativeEditor::detectSyntaxStyle(const std::string& token) {
    // Real keyword detection
    static const std::unordered_set<std::string> keywords = {
        "int", "float", "double", "char", "void", "bool",
        "if", "else", "for", "while", "do", "switch", "case", "break", "continue",
        "class", "struct", "union", "enum", "typedef", "namespace",
        "public", "private", "protected", "virtual", "override", "final",
        "return", "new", "delete", "sizeof", "static", "const", "constexpr",
        "template", "typename", "auto", "decltype"
    };
    
    if (keywords.contains(token)) {
        return 1; // Keyword style
    }
    
    return 0; // Default style
}

void NativeEditor::onKeyDown(WPARAM wParam, LPARAM lParam) {
    switch (wParam) {
        case VK_TAB:
            // Insert spaces
            for (int i = 0; i < m_tabSize; ++i) {
                insertChar(' ');
            }
            break;
            
        case VK_RETURN:
            insertChar('\n');
            break;
            
        case VK_BACK:
            deleteChar();
            break;
            
        case VK_DELETE:
            if (m_selection.isActive) {
                deleteText(m_selection.startLine, m_selection.startColumn,
                          m_selection.endLine, m_selection.endColumn);
                m_selection.isActive = false;
            } else {
                // Delete at cursor
                deleteText(m_cursorLine, m_cursorColumn, m_cursorLine, m_cursorColumn + 1);
            }
            break;
            
        case VK_LEFT:
            moveCursor(0, -1);
            break;
            
        case VK_RIGHT:
            moveCursor(0, 1);
            break;
            
        case VK_UP:
            moveCursor(-1, 0);
            break;
            
        case VK_DOWN:
            moveCursor(1, 0);
            break;
            
        case 'A':
            if (GetKeyState(VK_CONTROL) & 0x8000) {
                // Select all
                m_selection.startLine = 0;
                m_selection.startColumn = 0;
                m_selection.endLine = m_lines.size() - 1;
                m_selection.endColumn = m_lines.back().text.length();
                m_selection.isActive = true;
            }
            break;
            
        case 'C':
            if (GetKeyState(VK_CONTROL) & 0x8000) {
                copyToClipboard();
            }
            break;
            
        case 'V':
            if (GetKeyState(VK_CONTROL) & 0x8000) {
                pasteFromClipboard();
            }
            break;
            
        case 'X':
            if (GetKeyState(VK_CONTROL) & 0x8000) {
                cutToClipboard();
            }
            break;
            
        case VK_F12:
            // Build and run
            if (onBuildRequest) {
                onBuildRequest();
            }
            break;
    }
    
    ensureCursorVisible();
    updateScrollBars();
    
    if (onTextChanged) {
        onTextChanged();
    }
}

void NativeEditor::insertChar(char c) {
    if (m_selection.isActive) {
        // Replace selection
        deleteText(m_selection.startLine, m_selection.startColumn,
                  m_selection.endLine, m_selection.endColumn);
        m_selection.isActive = false;
    }
    
    // Ensure line exists
    if (m_cursorLine >= m_lines.size()) {
        m_lines.resize(m_cursorLine + 1);
    }
    
    // Insert character
    auto& line = m_lines[m_cursorLine];
    line.text.insert(m_cursorColumn, 1, c);
    line.renderedChars.clear(); // Force re-tokenization
    
    m_cursorColumn++;
    m_isModified = true;
    
    // Real-time syntax highlighting
    tokenizeLine(m_cursorLine);
    
    // Trigger diagnostics
    if (onTextChanged) {
        onTextChanged();
    }
}

void NativeEditor::showCompletionPopup(
    const std::vector<std::string>& completions,
    int line,
    int column
) {
    if (m_hWndCompletionPopup) {
        DestroyWindow(m_hWndCompletionPopup);
    }
    
    // Create completion popup window
    m_hWndCompletionPopup = CreateWindowEx(
        WS_EX_TOPMOST | WS_EX_TOOLWINDOW,
        "LISTBOX",
        "",
        WS_POPUP | WS_BORDER | LBS_NOTIFY,
        column * m_charWidth,
        (line - m_scrollOffset + 1) * m_charHeight,
        200,
        std::min(200, static_cast<int>(completions.size() * m_charHeight)),
        m_hWndEditor,
        nullptr,
        GetModuleHandle(nullptr),
        nullptr
    );
    
    // Add completions
    for (const auto& completion : completions) {
        SendMessage(m_hWndCompletionPopup, LB_ADDSTRING, 0, 
                   reinterpret_cast<LPARAM>(completion.c_str()));
    }
    
    ShowWindow(m_hWndCompletionPopup, SW_SHOW);
    SetFocus(m_hWndCompletionPopup);
    
    m_currentCompletions = completions;
    m_completionIndex = 0;
}

void NativeEditor::renderDiagnostics(HDC hdc) {
    // Real diagnostic rendering
    for (const auto& diagnostic : m_diagnostics) {
        if (diagnostic.line >= m_scrollOffset && 
            diagnostic.line < m_scrollOffset + 50) { // Visible range
            
            int yPos = (diagnostic.line - m_scrollOffset) * m_charHeight;
            
            // Draw squiggly underline
            HPEN pen = CreatePen(PS_SOLID, 1, 
                diagnostic.severity == 0 ? RGB(255, 0, 0) : // Error - red
                diagnostic.severity == 1 ? RGB(255, 255, 0) : // Warning - yellow
                RGB(0, 255, 0)); // Info - green
            
            HPEN oldPen = (HPEN)SelectObject(hdc, pen);
            
            int startX = m_showLineNumbers ? m_lineNumberWidth : 0;
            int endX = startX + 200; // Width of underline
            
            // Draw squiggly line
            for (int x = startX; x < endX; x += 4) {
                MoveToEx(hdc, x, yPos + m_charHeight - 2, nullptr);
                LineTo(hdc, x + 2, yPos + m_charHeight - 4);
                LineTo(hdc, x + 4, yPos + m_charHeight - 2);
            }
            
            SelectObject(hdc, oldPen);
            DeleteObject(pen);
            
            // Draw diagnostic message in status bar
            SetTextColor(hdc, RGB(200, 200, 200));
            TextOut(hdc, 10, yPos, diagnostic.message.c_str(), 
                   diagnostic.message.length());
        }
    }
}

