            static std::vector<std::string> matches;
            static size_t matchIndex = 0;
            
            if (state == 0) {
                matches.clear();
                matchIndex = 0;
                
                // Get CLI instance
                EnhancedCLI* cli = static_cast<EnhancedCLI*>(rl_get_startup_hook());
                if (cli) {
