                    for (const auto& cmd : commands) {
                        if (cmd.find(text) == 0) {
                            matches.push_back(cmd);
                        }
                    }
                }
            }
            
            if (matchIndex < matches.size()) {
                return strdup(matches[matchIndex++].c_str());
            }
            
            return nullptr;
        });
    };
    
    // Register built-in commands
    registerBuiltInCommands();
}

std::expected<std::string, CLIError> EnhancedCLI::executeCommand(const std::string& line) {
    if (line.empty()) {
        return "";
    }
    
    // Parse command and arguments
    auto argsResult = parseArguments(line);
    if (!argsResult) {
        return std::unexpected(argsResult.error());
    }
    
    auto args = argsResult.value();
    if (args.empty()) {
        return "";
    }
    
    std::string commandName = args[0];
    std::vector<std::string> commandArgs(args.begin() + 1, args.end());
    
    // Find command
    auto commandResult = findCommand(commandName);
    if (!commandResult) {
        return std::unexpected(commandResult.error());
    }
    
    Command* command = commandResult.value();
    
    // Execute with swarm mode if enabled
    if (m_swarmMode.load() && commandName != "swarm") {
        auto swarmResult = executeWithSwarm(commandName, commandArgs);
        if (swarmResult) {
            return swarmResult.value();
        }
    }
    
    // Execute with chain-of-thought if enabled
    if (m_chainOfThoughtEnabled.load() && commandName != "chain") {
        auto chainResult = executeWithChainOfThought(commandName, commandArgs);
        if (chainResult) {
            return chainResult.value();
        }
    }
    
    // Execute command
    return command->handler(commandArgs);
}

