std::string EnhancedCLI::applySyntaxHighlighting(const std::string& input) {
    // Real syntax highlighting for CLI
    std::string highlighted;
    size_t pos = 0;
    
    while (pos < input.length()) {
        if (isalpha(input[pos])) {
            // Token
            size_t start = pos;
            while (pos < input.length() && isalnum(input[pos])) pos++;
            
            std::string token = input.substr(start, pos - start);
            
            // Apply color based on token type
            if (token == "help" || token == "exit" || token == "status") {
                // Command - blue
                highlighted += "\033[34m" + token + "\033[0m";
            } else if (token == "generate" || token == "load" || token == "swarm") {
                // Action - green
                highlighted += "\033[32m" + token + "\033[0m";
            } else {
                highlighted += token;
            }
        } else if (input[pos] == '"') {
            // String - yellow
            highlighted += "\033[33m\"";
            pos++;
            
            while (pos < input.length() && input[pos] != '"') {
                highlighted += input[pos++];
            }
            
            if (pos < input.length()) {
                highlighted += "\"\033[0m";
                pos++;
            }
        } else {
            highlighted += input[pos++];
        }
    }
    
    return highlighted;
}

