std::expected<std::vector<int>, TokenError> TokenGenerator::bpeEncode(const std::string& text) {
    std::vector<int> tokens;
    
    // Split into words
    std::istringstream stream(text);
    std::string word;
    
    while (stream >> word) {
        // Start with character-level tokens
        std::vector<std::string> wordTokens;
        for (char c : word) {
            wordTokens.push_back(std::string(1, c));
        }
        
        // Apply BPE merges
        bool changed = true;
        while (changed) {
            changed = false;
            
            // Find best merge
            std::pair<std::string, std::string> bestMerge;
            int bestRank = -1;
            
            for (size_t i = 0; i + 1 < wordTokens.size(); ++i) {
                auto it = m_bpeMerges.find({wordTokens[i], wordTokens[i + 1]});
                if (it != m_bpeMerges.end() && it->second > bestRank) {
                    bestRank = it->second;
                    bestMerge = {wordTokens[i], wordTokens[i + 1]};
                }
            }
            
            // Apply merge
            if (bestRank >= 0) {
                for (size_t i = 0; i + 1 < wordTokens.size(); ++i) {
                    if (wordTokens[i] == bestMerge.first && 
                        wordTokens[i + 1] == bestMerge.second) {
                        wordTokens[i] = wordTokens[i] + wordTokens[i + 1];
                        wordTokens.erase(wordTokens.begin() + i + 1);
                        changed = true;
                        break;
                    }
                }
            }
        }
        
        // Convert to IDs
        for (const auto& token : wordTokens) {
            auto idResult = findToken(token);
            if (idResult) {
                tokens.push_back(idResult.value());
            } else {
                tokens.push_back(m_unkToken);
            }
        }
        
        // Add space token
        tokens.push_back(m_vocab[" "]);
    }
    
    // Remove trailing space
    if (!tokens.empty() && tokens.back() == m_vocab[" "]) {
        tokens.pop_back();
    }
    
    return tokens;
}

std::expected<std::string, TokenError> TokenGenerator::bpeDecode(const std::vector<int>& tokens) {
    std::string text;
    
    for (int tokenId : tokens) {
        auto tokenResult = findTokenString(tokenId);
        if (tokenResult) {
            text += tokenResult.value();
        } else {
            text += "<unk>";
        }
    }
    
    // Clean up spaces
    // Replace multiple spaces with single space
    size_t pos = 0;
    while ((pos = text.find("  ", pos)) != std::string::npos) {
        text.replace(pos, 2, " ");
    }
    
    // Trim leading/trailing spaces
    text.erase(0, text.find_first_not_of(" "));
    text.erase(text.find_last_not_of(" ") + 1);
    
    return text;
}

std::expected<int, TokenError> TokenGenerator::findToken(const std::string& token) {
    auto it = m_vocab.find(token);
    if (it != m_vocab.end()) {
        return it->second;
    }
    
    // Try subword tokens
    if (token.length() > 1) {
        // Check for prefix tokens
        std::string prefixToken = "▁" + token;
        it = m_vocab.find(prefixToken);
        if (it != m_vocab.end()) {
            return it->second;
        }
        
        // Check for suffix tokens
        std::string suffixToken = token + "</w>";
        it = m_vocab.find(suffixToken);
        if (it != m_vocab.end()) {
            return it->second;
        }
    }
    
    return std::unexpected(TokenError::TokenNotFound);
}

std::expected<std::string, TokenError> TokenGenerator::findTokenString(int tokenId) {
    auto it = m_idToToken.find(tokenId);
    if (it != m_idToToken.end()) {
        return it->second;
    }
    
    return std::unexpected(TokenError::TokenNotFound);
}

std::expected<void, TokenError> TokenGenerator::loadVocabulary(
    const std::string& vocabPath
) {
    std::lock_guard lock(m_mutex);
    
    std::ifstream file(vocabPath);
    if (!file) {
        return std::unexpected(TokenError::VocabularyNotLoaded);
    }
    
    m_vocab.clear();
    m_idToToken.clear();
    
    std::string line;
    int id = 0;
    
    while (std::getline(file, line)) {
        if (!line.empty()) {
            m_vocab[line] = id;
            m_idToToken[id] = line;
            id++;
        }
    }
    
    // Set special tokens
    if (m_vocab.contains("<s>")) m_bosToken = m_vocab["<s>"];
    if (m_vocab.contains("</s>")) m_eosToken = m_vocab["</s>"];
    if (m_vocab.contains("<pad>")) m_padToken = m_vocab["<pad>"];
    if (m_vocab.contains("<unk>")) m_unkToken = m_vocab["<unk>"];
    
    return {};
}

