#include "agentic_ide.h"
#include "enhanced_cli.h"
#include "swarm_orchestrator.h"
#include "chain_of_thought.h"
#include "CLI11.hpp"
#include <spdlog/spdlog.h>

int main(int argc, char* argv[]) {
    CLI::App app{"RawrXD v3.0 - Complete Agentic IDE with Swarm & Chain-of-Thought"};
    
    // Mode selection
    std::string mode = "gui";
    app.add_option("-m,--mode", mode, "Mode: gui, cli, server, swarm, chain")
        ->default_val("gui")
        ->check(CLI::IsMember({"gui", "cli", "server", "swarm", "chain"}));
    
    // Configuration
    std::string configPath = "./config.json";
    app.add_option("-c,--config", configPath, "Configuration file path");
    
    // Logging
    std::string logLevel = "info";
    app.add_option("-l,--log-level", logLevel, "Log level: trace, debug, info, warn, error")
        ->default_val("info")
        ->check(CLI::IsMember({"trace", "debug", "info", "warn", "error"}));
    
    // Swarm mode options
    int swarmAgents = 4;
    app.add_option("--swarm-agents", swarmAgents, "Number of swarm agents")
        ->default_val(4);
    
    // Chain-of-thought options
    bool enableChain = false;
    app.add_flag("--chain", enableChain, "Enable chain-of-thought reasoning");
    
    // Model path
    std::string modelPath;
    app.add_option("--model", modelPath, "Path to GGUF model");
    
    // Headless mode
    bool headless = false;
    app.add_flag("--headless", headless, "Run in headless mode");
    
    CLI11_PARSE(app, argc, argv);
    
    // Setup logging
    spdlog::set_level(spdlog::level::from_str(logLevel));
    spdlog::set_pattern("[%Y-%m-%d %H:%M:%S.%e] [%^%l%$] %v");
    
    // Load configuration
    IDEConfig config;
    if (fs::exists(configPath)) {
        std::ifstream configFile(configPath);
        json configJson;
        configFile >> configJson;
        
        config.modelsPath = configJson.value("models_path", "./models");
        config.toolsPath = configJson.value("tools_path", "./tools");
        config.maxWorkers = configJson.value("max_workers", 4);
        config.maxMemoryMB = configJson.value("max_memory_mb", 8192);
        config.logLevel = logLevel;
        config.enableFileLogging = configJson.value("enable_file_logging", true);
        config.logPath = configJson.value("log_path", "./logs/agentic_ide.log");
        config.enableLSP = configJson.value("enable_lsp", true);
        config.enableChat = configJson.value("enable_chat", true);
        config.enableOrchestrator = configJson.value("enable_orchestrator", true);
        config.enableZeroDay = configJson.value("enable_zero_day", true);
        config.apiKey = configJson.contains("api_key") ? 
            std::optional<std::string>{configJson["api_key"]} : std::nullopt;
    }
    
    // Override with CLI args
    if (!modelPath.empty()) {
        config.modelsPath = fs::path(modelPath).parent_path().string();
    }
    
    // Create IDE
    auto ide = std::make_shared<AgenticIDE>(config);
    
    // Initialize
    auto initResult = ide->initialize();
    if (!initResult) {
        spdlog::critical("IDE initialization failed: {}", 
            static_cast<int>(initResult.error()));
        return 1;
    }
    
    // Start
    auto startResult = ide->start();
    if (!startResult) {
        spdlog::critical("IDE start failed: {}", 
            static_cast<int>(startResult.error()));
        return 1;
    }
    
    // Run based on mode
    if (mode == "gui" && !headless) {
        // Create native GUI
        NativeEditor guiEditor;
        ide->setEditor(&guiEditor);
        
        // Show status
        auto status = ide->getStatus();
        spdlog::info("IDE Status: {}", status.dump(2));
        
        guiEditor.run();
    } else if (mode == "cli") {
        // Create enhanced CLI
        EnhancedCLI cli;
        
        // Register IDE commands
        cli.registerCommand({
            "status",
            "Show IDE status",
            {"st"},
            [ide](const std::vector<std::string>& args) {
                auto status = ide->getStatus();
                return std::expected<std::string, CLIError>(status.dump(2));
            },
            "status",
            "Display current IDE status"
        });
        
        cli.registerCommand({
            "generate",
            "Generate using IDE inference engine",
            {"gen"},
            [ide](const std::vector<std::string>& args) {
                if (args.empty()) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::InvalidArguments)
                    );
                }
                
                auto result = ide->getInferenceEngine()->generate(
                    args[0], 0.7f, 0.9f, args.size() > 1 ? std::stoi(args[1]) : 512
                );
                
                if (!result) {
                    return std::expected<std::string, CLIError>(
                        std::unexpected(CLIError::ExecutionFailed)
                    );
                }
                
                return result->text;
            },
            "generate <prompt> [max_tokens]",
            "Generate text using the IDE's inference engine"
        });
        
        // Run CLI
        auto cliResult = cli.runInteractive();
        if (!cliResult) {
            spdlog::error("CLI error: {}", static_cast<int>(cliResult.error()));
        }
    } else if (mode == "server") {
        // Create HTTP server
        auto server = std::make_unique<GGUFAlpacaServer>(config.port);
        
        // Add swarm endpoint
        server->addEndpoint("/api/swarm", [ide](const json& req) {
            std::string task = req.value("task", "");
            auto swarm = SwarmOrchestrator();
            return swarm.executeTask(task);
        });
        
        // Add chain endpoint
        server->addEndpoint("/api/chain", [ide](const json& req) {
            std::string goal = req.value("goal", "");
            auto context = req.value("context", json::object());
            auto chain = ChainOfThought();
            return chain.generateChain(goal, context);
        });
        
        server->run();
    } else if (mode == "swarm") {
        // Run in swarm mode
        spdlog::info("Starting swarm mode with {} agents", swarmAgents);
        
        SwarmOrchestrator swarm(swarmAgents);
        
        // Interactive swarm mode
        while (true) {
            char* input = readline("swarm> ");
            if (!input) break;
            
            if (*input) {
                add_history(input);
                
                auto result = swarm.executeTask(input);
                if (result) {
                    std::cout << "Swarm result: " << result.value() << "\n";
                } else {
                    std::cerr << "Swarm error: " << static_cast<int>(result.error()) << "\n";
                }
                
                free(input);
            }
        }
    } else if (mode == "chain") {
        // Run in chain-of-thought mode
        spdlog::info("Starting chain-of-thought mode");
        
        ChainOfThought chain;
        
        // Interactive chain mode
        while (true) {
            char* input = readline("chain> ");
            if (!input) break;
            
            if (*input) {
                add_history(input);
                
                auto context = std::unordered_map<std::string, std::string>{
                    {"user_input", input},
                    {"mode", "interactive"}
                };
                
                auto result = chain.generateChain(input, context);
                if (result) {
                    auto explanation = chain.generateExplanation(result.value());
                    if (explanation) {
                        std::cout << "Chain of thought:\n" << explanation.value() << "\n";
                    }
                } else {
                    std::cerr << "Chain error: " << static_cast<int>(result.error()) << "\n";
                }
                
                free(input);
            }
        }
    }
    
    // Cleanup
    ide->stop();
    
    spdlog::info("RawrXD v3.0 shutdown complete");
    return 0;
}
